-- Corrige os valores realizados do Book Paris & Lisboa
-- Execute no Supabase SQL Editor depois da importação.
do $$
declare target_user uuid; trip_id_var uuid;
begin
  select id into target_user from auth.users where lower(email)=lower('cintiapfs@gmail.com') limit 1;
  select id into trip_id_var from public.trips where user_id=target_user and name='Paris & Lisboa' limit 1;
  if trip_id_var is null then raise exception 'Viagem não encontrada para esta conta.'; end if;
  update public.budget_items set actual_amount=18190.94 where trip_id=trip_id_var and label='Passagens Internacionais (Brasil ↔ Lisboa) — British Airways';\n  update public.budget_items set actual_amount=4671.44 where trip_id=trip_id_var and label='Aéreos Intra-Europa (Lisboa ↔ Paris-Beauvais) · Ryanair';\n  update public.budget_items set actual_amount=4000.00 where trip_id=trip_id_var and label='Escolha de assentos nos voos';\n  update public.budget_items set actual_amount=996.20 where trip_id=trip_id_var and label='Transfer Beauvais ↔ Paris Centro — ônibus / Royal Transfer / SIXT';\n  update public.budget_items set actual_amount=12260.00 where trip_id=trip_id_var and label='Yooma Urban Lodge Paris — 2 Quartos · 8 Noites';\n  update public.budget_items set actual_amount=942.64 where trip_id=trip_id_var and label='Hotel Jardim Lisboa — 1 Noite (19/11)';\n  update public.budget_items set actual_amount=2710.00 where trip_id=trip_id_var and label='Your Lisbon Home Parque das Nações — 2 Noites (29–30/11)';\n  update public.budget_items set actual_amount=849.70 where trip_id=trip_id_var and label='Torre Eiffel — 5 pessoas (2º andar)';\n  update public.budget_items set actual_amount=210.96 where trip_id=trip_id_var and label='Louvre — 2 adultos (menores de 18: gratuito)';\n  update public.budget_items set actual_amount=879.00 where trip_id=trip_id_var and label='Versalhes — Passaporte Completo · 5 pessoas';\n  update public.budget_items set actual_amount=351.60 where trip_id=trip_id_var and label='Minicarro Elétrico Privativo — Jardins de Versalhes';\n  update public.budget_items set actual_amount=439.50 where trip_id=trip_id_var and label='Bateaux-Mouches — Cruzeiro Noturno · 5 pessoas';\n  update public.budget_items set actual_amount=3334.86 where trip_id=trip_id_var and label='Disneyland Paris — 5 pessoas · 1 dia · 2 parques · COMPRADO';\n  update public.budget_items set actual_amount=204.10 where trip_id=trip_id_var and label='Grande Galerie de l''Évolution — 5 pessoas';\n  update public.budget_items set actual_amount=556.70 where trip_id=trip_id_var and label='Lumières en Seine · 5 pessoas (confirmar set/out 2026)';\n  update public.budget_items set actual_amount=703.20 where trip_id=trip_id_var and label='Parque dos Príncipes — PSG · 5 pessoas (confirmar ago 2026)';\n  update public.budget_items set actual_amount=468.80 where trip_id=trip_id_var and label='Oceanário de Lisboa · 5 pessoas';\n  update public.budget_items set actual_amount=293.00 where trip_id=trip_id_var and label='Castelo de São Jorge · 5 pessoas';\n  update public.budget_items set actual_amount=8883.05 where trip_id=trip_id_var and label='Apple — reserva definida para 5 pessoas';\n  update public.budget_items set actual_amount=1467.50 where trip_id=trip_id_var and label='Perfumes — compras pontuais, sem marcas de luxo em excesso';\n  update public.budget_items set actual_amount=2054.50 where trip_id=trip_id_var and label='Roupas — peças selecionadas para a família';\n  update public.budget_items set actual_amount=880.50 where trip_id=trip_id_var and label='Lembrancinhas — pequenas lembranças para os cinco';
end $$;
